def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 1:
            priorities[i] = np.inf
            continue
        score = 0
        for j in range(1, 10):
            term = (1 / j**2) * (ratio ** j)
            if j % 2 == 0:
                term *= 1.1
            else:
                term *= 0.9
            score += term
        remaining = capacity - item
        if remaining < 0.05 * capacity:
            score *= 2
        elif remaining < 0.15 * capacity:
            score *= 1.3
        else:
            score *= 0.85
        if int(capacity) % 3 == 0:
            score -= 0.05 * (capacity / 10)
        elif int(capacity) % 5 == 0:
            score -= 0.1 * (capacity / 20)
        else:
            score -= 0.02 * (capacity / 30)
        penalty = 0
        for k in range(1, 4):
            if abs(capacity - item*k) < 0.01 * capacity:
                penalty += 0.2 * k
        score += penalty
        if score < 0:
            score = 0
        priorities[i] = score
    return priorities
